const body = $input.first().json.body || $input.first().json;
const message   = body.message   || '';
const sessionId = body.sessionId || 'default';
if (!message.trim()) throw new Error('Empty message');
return [{ json: { message, sessionId } }];

// Build context from Qdrant search results and prepare the prompt
const message   = $('Parse Input').first().json.message;
const searchResult = $input.first().json;

const hits = (searchResult.result || []).filter(h => h.payload && h.payload.text);

let context = '';
const sources = [];

if (hits.length > 0) {
  context = hits.map((h, i) => {
    const fn  = h.payload.filename || 'unknown';
    const txt = h.payload.text     || '';
    sources.push({ file: fn, excerpt: txt.slice(0, 200), score: Math.round((h.score || 0) * 100) });
    return `[Source ${i+1}: ${fn}]\n${txt}`;
  }).join('\n\n---\n\n');
}

const systemPrompt = context
  ? `You are a helpful assistant for Riga City Council.\nAnswer the user's question using ONLY the context below.\nIf the context does not contain enough information, say so clearly.\nAnswer in the same language as the question (Latvian or English).\n\nCONTEXT:\n${context}`
  : 'You are a helpful assistant for Riga City Council. No documents have been indexed yet, so answer from your general knowledge. Answer in the same language as the question.';

return [{ json: { message, systemPrompt, sources } }];

const ollamaResp = $input.first().json;
const answer  = ollamaResp.message?.content || 'Sorry, I could not generate a response.';
const sources = $('Build RAG Prompt').first().json.sources || [];
return [{ json: { answer, sources } }];
